import React, { useCallback, useState } from 'react';
import { useDropzone } from 'react-dropzone';
import { resumeService } from '../services/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Upload, FileText, X, CheckCircle } from 'lucide-react';

const ResumeUpload = ({ onUploadSuccess }) => {
  const { user } = useAuth();
  const [uploading, setUploading] = useState(false);
  const [uploadedFile, setUploadedFile] = useState(null);

  const onDrop = useCallback(async (acceptedFiles) => {
    const file = acceptedFiles[0];
    if (!file) return;

    // Validate file type
    if (!file.type.includes('pdf') && !file.type.includes('doc')) {
      toast.error('Please upload a PDF or DOC file');
      return;
    }

    // Validate file size (max 5MB)
    if (file.size > 5 * 1024 * 1024) {
      toast.error('File size must be less than 5MB');
      return;
    }

    setUploading(true);
    try {
      const response = await resumeService.uploadResume(file, user.user_id);
      toast.success('Resume uploaded successfully!');
      setUploadedFile({
        name: file.name,
        id: response.resume_id
      });
      onUploadSuccess && onUploadSuccess(response);
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Failed to upload resume');
    } finally {
      setUploading(false);
    }
  }, [user.user_id, onUploadSuccess]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'application/pdf': ['.pdf'],
      'application/msword': ['.doc'],
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document': ['.docx']
    },
    multiple: false
  });

  const removeFile = () => {
    setUploadedFile(null);
  };

  return (
    <div className="card">
      <div className="card-header">
        <h3 className="card-title">Upload Your Resume</h3>
        <p className="text-gray-600">Upload your resume in PDF or DOC format to get started with the analysis.</p>
      </div>

      {!uploadedFile ? (
        <div
          {...getRootProps()}
          className={`upload-zone ${isDragActive ? 'active' : ''} ${uploading ? 'loading' : ''}`}
        >
          <input {...getInputProps()} />
          <Upload size={48} style={{ color: '#667eea', marginBottom: '16px' }} />
          {uploading ? (
            <div>
              <p className="text-lg font-bold">Uploading...</p>
              <p className="text-gray-600">Please wait while we process your resume</p>
            </div>
          ) : isDragActive ? (
            <div>
              <p className="text-lg font-bold">Drop your resume here</p>
              <p className="text-gray-600">Release to upload</p>
            </div>
          ) : (
            <div>
              <p className="text-lg font-bold">Drop your resume here, or click to browse</p>
              <p className="text-gray-600">Supports PDF, DOC, and DOCX files up to 5MB</p>
            </div>
          )}
        </div>
      ) : (
        <div className="card" style={{ background: '#f0f9ff', border: '1px solid #0ea5e9' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <CheckCircle size={24} style={{ color: '#22c55e' }} />
              <div>
                <p className="font-bold">{uploadedFile.name}</p>
                <p className="text-gray-600">Resume uploaded successfully</p>
              </div>
            </div>
            <button
              onClick={removeFile}
              className="btn btn-secondary"
              style={{ padding: '8px' }}
            >
              <X size={16} />
            </button>
          </div>
        </div>
      )}

      {uploadedFile && (
        <div className="mt-4 text-center">
          <p className="text-gray-600">
            Great! Your resume has been uploaded. Now you can proceed with the analysis.
          </p>
        </div>
      )}
    </div>
  );
};

export default ResumeUpload;
